import React, { useState, useEffect } from 'react';
import ReactDOM from 'react-dom/client';

const OIDC_CONFIG = {
  authorizationEndpoint: 'https://your-idp.example.com/oauth2/authorize',
  tokenEndpoint: 'https://your-idp.example.com/oauth2/token',
  clientId: 'your-client-id',
  redirectUri: window.location.origin + '/callback',
  scope: 'openid profile email'
};

const ALLOWED_ISSUERS = ['https://your-idp.example.com'];

function generateRandomString(length) {
  const array = new Uint8Array(length);
  window.crypto.getRandomValues(array);
  return Array.from(array, byte => byte.toString(16).padStart(2, '0')).join('');
}

async function generateCodeChallenge(codeVerifier) {
  const encoder = new TextEncoder();
  const data = encoder.encode(codeVerifier);
  const hash = await window.crypto.subtle.digest('SHA-256', data);
  return btoa(String.fromCharCode(...new Uint8Array(hash)))
    .replace(/\+/g, '-')
    .replace(/\//g, '_')
    .replace(/=/g, '');
}

function base64UrlDecode(str) {
  let base64 = str.replace(/-/g, '+').replace(/_/g, '/');
  while (base64.length % 4) {
    base64 += '=';
  }
  return JSON.parse(atob(base64));
}

function validateIdToken(idToken, nonce) {
  try {
    const parts = idToken.split('.');
    if (parts.length !== 3) {
      throw new Error('Invalid token format');
    }

    const payload = base64UrlDecode(parts[1]);

    if (!payload.iss || !ALLOWED_ISSUERS.includes(payload.iss)) {
      throw new Error('Invalid issuer');
    }

    if (payload.aud !== OIDC_CONFIG.clientId) {
      throw new Error('Invalid audience');
    }

    const now = Math.floor(Date.now() / 1000);
    if (payload.exp && payload.exp < now) {
      throw new Error('Token expired');
    }

    if (payload.nbf && payload.nbf > now) {
      throw new Error('Token not yet valid');
    }

    if (payload.nonce !== nonce) {
      throw new Error('Invalid nonce');
    }

    return payload;
  } catch (error) {
    console.error('Token validation failed:', error.message);
    throw error;
  }
}

function SecureStorage() {
  const storage = sessionStorage;
  const prefix = 'oidc_';

  return {
    set: (key, value) => {
      storage.setItem(prefix + key, JSON.stringify(value));
    },
    get: (key) => {
      const item = storage.getItem(prefix + key);
      return item ? JSON.parse(item) : null;
    },
    remove: (key) => {
      storage.removeItem(prefix + key);
    },
    clear: () => {
      Object.keys(storage).forEach(key => {
        if (key.startsWith(prefix)) {
          storage.removeItem(key);
        }
      });
    }
  };
}

const secureStorage = SecureStorage();

async function initiateLogin() {
  const state = generateRandomString(32);
  const nonce = generateRandomString(32);
  const codeVerifier = generateRandomString(64);
  const codeChallenge = await generateCodeChallenge(codeVerifier);

  secureStorage.set('state', state);
  secureStorage.set('nonce', nonce);
  secureStorage.set('code_verifier', codeVerifier);

  const params = new URLSearchParams({
    response_type: 'code',
    client_id: OIDC_CONFIG.clientId,
    redirect_uri: OIDC_CONFIG.redirectUri,
    scope: OIDC_CONFIG.scope,
    state: state,
    nonce: nonce,
    code_challenge: codeChallenge,
    code_challenge_method: 'S256'
  });

  window.location.href = `${OIDC_CONFIG.authorizationEndpoint}?${params.toString()}`;
}

async function handleCallback() {
  const params = new URLSearchParams(window.location.search);
  const code = params.get('code');
  const state = params.get('state');
  const error = params.get('error');

  if (error) {
    throw new Error(`Authentication error: ${error}`);
  }

  if (!code || !state) {
    throw new Error('Missing required parameters');
  }

  const storedState = secureStorage.get('state');
  if (!storedState || state !== storedState) {
    throw new Error('State mismatch - possible CSRF attack');
  }

  const nonce = secureStorage.get('nonce');
  const codeVerifier = secureStorage.get('code_verifier');

  if (!nonce || !codeVerifier) {
    throw new Error('Missing stored authentication data');
  }

  secureStorage.remove('state');

  const tokenParams = new URLSearchParams({
    grant_type: 'authorization_code',
    code: code,
    redirect_uri: OIDC_CONFIG.redirectUri,
    client_id: OIDC_CONFIG.clientId,
    code_verifier: codeVerifier
  });

  const response = await fetch(OIDC_CONFIG.tokenEndpoint, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/x-www-form-urlencoded'
    },
    body: tokenParams.toString()
  });

  if (!response.ok) {
    throw new Error('Token exchange failed');
  }

  const tokens = await response.json();

  if (!tokens.id_token || !tokens.access_token) {
    throw new Error('Invalid token response');
  }

  const userProfile = validateIdToken(tokens.id_token, nonce);

  secureStorage.remove('nonce');
  secureStorage.remove('code_verifier');

  secureStorage.set('access_token', tokens.access_token);
  secureStorage.set('user_profile', userProfile);

  if (tokens.refresh_token) {
    secureStorage.set('refresh_token', tokens.refresh_token);
  }

  window.history.replaceState({}, document.title, '/');

  return userProfile;
}

function logout() {
  secureStorage.clear();
  window.location.href = '/';
}

function App() {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    const initAuth = async () => {
      try {
        const params = new URLSearchParams(window.location.search);
        
        if (params.has('code')) {
          const userProfile = await handleCallback();
          setUser(userProfile);
        } else {
          const storedProfile = secureStorage.get('user_profile');
          const storedToken = secureStorage.get('access_token');
          
          if (storedProfile && storedToken) {
            setUser(storedProfile);
          }
        }
      } catch (err) {
        setError(err.message);
        secureStorage.clear();
      } finally {
        setLoading(false);
      }
    };

    initAuth();
  }, []);

  if (loading) {
    return <div style={styles.container}><div style={styles.loading}>Loading...</div></div>;
  }

  if (error) {
    return (
      <div style={styles.container}>
        <div style={styles.error}>
          <h2>Authentication Error</h2>
          <p>{error}</p>
          <button onClick={() => { setError(null); window.location.href = '/'; }} style={styles.button}>
            Try Again
          </button>
        </div>
      </div>
    );
  }

  if (!user) {
    return (
      <div style={styles.container}>
        <div style={styles.loginBox}>
          <h1>Secure OIDC Authentication</h1>
          <p>Please log in to continue</p>
          <button onClick={initiateLogin} style={styles.button}>
            Login with OpenID Connect
          </button>
        </div>
      </div>
    );
  }

  return (
    <div style={styles.container}>
      <div style={styles.profileBox}>
        <h1>Welcome!</h1>
        <div style={styles.profileInfo}>
          <p><strong>Subject:</strong> {user.sub}</p>
          {user.name && <p><strong>Name:</strong> {user.name}</p>}
          {user.email && <p><strong>Email:</strong> {user.email}</p>}
          {user.preferred_username && <p><strong>Username:</strong> {user.preferred_username}</p>}
        </div>
        <button onClick={logout} style={styles.logoutButton}>
          Logout
        </button>
      </div>
    </div>
  );
}

